   209	/**
   210	 * Extract task metadata from the task plan file on disk.
   211	 */
   212	function extractTaskMetadata(unitId: string, basePath: string): TaskMetadata {
   213	  const meta: TaskMetadata = {};
   214	  const { milestone: mid, slice: sid, task: tid } = parseUnitId(unitId);
   215	  if (!mid || !sid || !tid) return meta;
   216	  const taskPlanPath = join(gsdRoot(basePath), mid, "slices", sid, "tasks", `${tid}-PLAN.md`);
   217	
   218	  try {
   219	    if (!existsSync(taskPlanPath)) return meta;
   220	    const content = readFileSync(taskPlanPath, "utf-8");
   221	    const lines = content.split("\n");
   222	
   223	    // Count files mentioned in "Files:" or "- Files:" lines
   224	    const fileLines = lines.filter(l => /^\s*-?\s*files?\s*:/i.test(l));
   225	    if (fileLines.length > 0) {
   226	      // Count comma-separated or bullet-pointed files
   227	      const allFiles = new Set<string>();
   228	      for (const line of fileLines) {
   229	        const filesStr = line.replace(/^\s*-?\s*files?\s*:\s*/i, "");
   230	        const files = filesStr.split(/[,;]/).map(f => f.trim()).filter(Boolean);
   231	        files.forEach(f => allFiles.add(f));
   232	      }
   233	      meta.fileCount = allFiles.size;
   234	    }
   235	
   236	    // Check for "new file" or "create" keywords
   237	    meta.isNewFile = lines.some(l => /\b(create|new file|scaffold|bootstrap)\b/i.test(l));
   238	
   239	    // Look for tags/labels in frontmatter or content
   240	    const tags: string[] = [];
   241	    if (content.match(/\b(refactor|migration|architect)/i)) tags.push("refactor");
   242	    if (content.match(/\b(test|spec|coverage)\b/i)) tags.push("test");
   243	    if (content.match(/\b(doc|readme|comment|jsdoc)\b/i)) tags.push("docs");
   244	    if (content.match(/\b(config|env|setting)\b/i)) tags.push("config");
   245	    if (content.match(/\b(rename|typo|spelling)\b/i)) tags.push("rename");
   246	    meta.tags = tags;
   247	
   248	    // Try to extract estimated lines from content
   249	    const estimateMatch = content.match(/~?\s*(\d+)\s*lines?\b/i);
   250	    if (estimateMatch) {
   251	      meta.estimatedLines = parseInt(estimateMatch[1], 10);
   252	    }
   253	
   254	    // Phase 4: Deeper introspection signals
   255	
   256	    // Count fenced code blocks (```) — more code blocks = more complex implementation
   257	    const codeBlockMatches = content.match(/^```/gm);
   258	    meta.codeBlockCount = codeBlockMatches ? Math.floor(codeBlockMatches.length / 2) : 0;
   259	
   260	    // Detect complexity keywords that suggest harder tasks
   261	    const complexityKeywords: string[] = [];
   262	    if (content.match(/\b(migration|migrate|schema change)\b/i)) complexityKeywords.push("migration");
   263	    if (content.match(/\b(architect|design pattern|system design)\b/i)) complexityKeywords.push("architecture");
   264	    if (content.match(/\b(security|auth|encrypt|credential|vulnerability)\b/i)) complexityKeywords.push("security");
   265	    if (content.match(/\b(performance|optimize|cache|index)\b/i)) complexityKeywords.push("performance");
   266	    if (content.match(/\b(concurrent|parallel|race condition|mutex|lock)\b/i)) complexityKeywords.push("concurrency");
   267	    if (content.match(/\b(backward.?compat|breaking change|deprecat)\b/i)) complexityKeywords.push("compatibility");
   268	    meta.complexityKeywords = complexityKeywords;
   269	  } catch {
   270	    // Non-fatal — metadata extraction is best-effort
   271	  }
   272	
   273	  return meta;
   274	}
