   276	// ─── Budget Pressure ─────────────────────────────────────────────────────────
   277	
   278	/**
   279	 * Apply budget pressure to a classification result.
   280	 * As budget usage increases, more aggressively downgrade tiers.
   281	 *
   282	 * - <50%:   Normal classification (no change)
   283	 * - 50-75%: Tier 2 → Tier 1 where possible
   284	 * - 75-90%: Only heavy tasks keep configured model
   285	 * - >90%:   Everything except replan-slice gets cheapest model
   286	 */
   287	function applyBudgetPressure(
   288	  result: ClassificationResult,
   289	  budgetPct?: number,
   290	): ClassificationResult {
   291	  if (budgetPct === undefined || budgetPct < 0.5) return result;
   292	
   293	  const original = result.tier;
   294	
   295	  if (budgetPct >= 0.9) {
   296	    // >90%: almost everything goes to light
   297	    if (result.tier !== "heavy") {
   298	      result.tier = "light";
   299	    } else {
   300	      // Even heavy gets downgraded to standard
   301	      result.tier = "standard";
   302	    }
   303	  } else if (budgetPct >= 0.75) {
   304	    // 75-90%: only heavy stays, everything else goes to light
   305	    if (result.tier === "standard") {
   306	      result.tier = "light";
   307	    }
   308	  } else {
   309	    // 50-75%: standard → light
   310	    if (result.tier === "standard") {
   311	      result.tier = "light";
   312	    }
   313	  }
   314	
   315	  if (result.tier !== original) {
   316	    result.downgraded = true;
   317	    result.reason = `${result.reason} (budget pressure: ${Math.round(budgetPct * 100)}%)`;
   318	  }
   319	
   320	  return result;
   321	}
