// Reproduction script for unknown model dynamic routing bug
import { resolveModelForComplexity, defaultRoutingConfig } from "../model-router.js";
import type { ClassificationResult } from "../complexity-classifier.js";

function makeClassification(tier, reason = "test") {
  return { tier, reason, downgraded: false };
}

const AVAILABLE_MODELS = [
  "claude-opus-4-6",
  "claude-sonnet-4-6",
  "claude-haiku-4-5",
  "gpt-4o-mini",
  "qwen3.5-plus",
];

// ─── Scenario from issue: planning: gpt-5.4 with tier_models ─────────────────

console.log("=== Reproduction: unknown model (gpt-5.4) gets downgraded ===");

const routingConfig = {
  ...defaultRoutingConfig(),
  enabled: true,
  tier_models: {
    light: "qwen3.5-plus",
    standard: "qwen3.5-plus",
    heavy: "gpt-5.4",
  },
};

// User configured planning: gpt-5.4, but gpt-5.4 is not in MODEL_CAPABILITY_TIER
const result1 = resolveModelForComplexity(
  makeClassification("standard", "plan-slice standard complexity"),
  { primary: "gpt-5.4", fallbacks: [] },
  routingConfig,
  AVAILABLE_MODELS,
);

console.log(`  modelId: ${result1.modelId}`);
console.log(`  wasDowngraded: ${result1.wasDowngraded}`);
console.log(`  reason: ${result1.reason}`);
console.log(`  tier: ${result1.tier}`);

// BUG: modelId should be "gpt-5.4" (user's explicit config), but is "qwen3.5-plus"
if (result1.modelId === "gpt-5.4") {
  console.log("  PASS: Unknown model preserved (was not downgraded)");
} else if (result1.modelId === "qwen3.5-plus") {
  console.log("  FAIL: Unknown model was incorrectly downgraded to qwen3.5-plus");
  process.exit(1);
} else {
  console.log(`  UNEXPECTED: modelId = ${result1.modelId}`);
  process.exit(1);
}

// ─── Known model should still downgrade correctly ─────────────────────────────

console.log("\n=== Regression: known model (claude-opus-4-6) still downgrades ===");

const result2 = resolveModelForComplexity(
  makeClassification("standard", "standard complexity"),
  { primary: "claude-opus-4-6", fallbacks: [] },
  routingConfig,
  AVAILABLE_MODELS,
);

console.log(`  modelId: ${result2.modelId}`);
console.log(`  wasDowngraded: ${result2.wasDowngraded}`);

// Known model should still downgrade (opus is heavy, standard tier should get sonnet or tier_models)
if (result2.wasDowngraded) {
  console.log("  PASS: Known model correctly downgraded");
} else {
  console.log("  FAIL: Known model was NOT downgraded when it should have been");
  process.exit(1);
}

// ─── Unknown model with matching tier (heavy classification) ──────────────────

console.log("\n=== Unknown model with heavy classification ===");

const result3 = resolveModelForComplexity(
  makeClassification("heavy", "heavy complexity"),
  { primary: "gpt-5.4", fallbacks: [] },
  routingConfig,
  AVAILABLE_MODELS,
);

console.log(`  modelId: ${result3.modelId}`);
console.log(`  wasDowngraded: ${result3.wasDowngraded}`);

if (result3.modelId === "gpt-5.4" && !result3.wasDowngraded) {
  console.log("  PASS: Unknown model preserved for heavy classification");
} else {
  console.log("  FAIL: Unknown model not handled correctly for heavy classification");
  process.exit(1);
}

console.log("\n=== All checks passed ===");

