    85	/**
    86	 * Resolve the model to use for a given complexity tier.
    87	 *
    88	 * Downgrade-only: the returned model is always equal to or cheaper than
    89	 * the user's configured primary model. Never upgrades beyond configuration.
    90	 *
    91	 * @param classification  The complexity classification result
    92	 * @param phaseConfig     The user's configured model for this phase (ceiling)
    93	 * @param routingConfig   Dynamic routing configuration
    94	 * @param availableModelIds  List of available model IDs (from registry)
    95	 */
    96	export function resolveModelForComplexity(
    97	  classification: ClassificationResult,
    98	  phaseConfig: ResolvedModelConfig | undefined,
    99	  routingConfig: DynamicRoutingConfig,
   100	  availableModelIds: string[],
   101	): RoutingDecision {
   102	  // If no phase config or routing disabled, pass through
   103	  if (!phaseConfig || !routingConfig.enabled) {
   104	    return {
   105	      modelId: phaseConfig?.primary ?? "",
   106	      fallbacks: phaseConfig?.fallbacks ?? [],
   107	      tier: classification.tier,
   108	      wasDowngraded: false,
   109	      reason: "dynamic routing disabled or no phase config",
   110	    };
   111	  }
   112	
   113	  const configuredPrimary = phaseConfig.primary;
   114	  const configuredTier = getModelTier(configuredPrimary);
   115	  const requestedTier = classification.tier;
   116	
   117	  // When the user explicitly configured an unknown model (not in our tier map),
   118	  // respect their choice and do not downgrade. The unknown model is their
   119	  // deliberate selection for this phase.
   120	  if (!isKnownModel(configuredPrimary)) {
   121	    return {
   122	      modelId: configuredPrimary,
   123	      fallbacks: phaseConfig.fallbacks,
   124	      tier: requestedTier,
   125	      wasDowngraded: false,
   126	      reason: `unknown model ${configuredPrimary} — preserving explicit phase config`,
   127	    };
   128	  }
   129	
   130	  // Downgrade-only: if requested tier >= configured tier, no change
   131	  if (tierOrdinal(requestedTier) >= tierOrdinal(configuredTier)) {
   132	    return {
   133	      modelId: configuredPrimary,
   134	      fallbacks: phaseConfig.fallbacks,
   135	      tier: requestedTier,
   136	      wasDowngraded: false,
   137	      reason: `tier ${requestedTier} >= configured ${configuredTier}`,
   138	    };
   139	  }
   140	
   141	  // Find the best model for the requested tier
   142	  const targetModelId = findModelForTier(
   143	    requestedTier,
   144	    routingConfig,
   145	    availableModelIds,
   146	    routingConfig.cross_provider !== false,
   147	  );
   148	
   149	  if (!targetModelId) {
   150	    // No suitable model found — use configured primary
   151	    return {
   152	      modelId: configuredPrimary,
   153	      fallbacks: phaseConfig.fallbacks,
   154	      tier: requestedTier,
   155	      wasDowngraded: false,
   156	      reason: `no ${requestedTier}-tier model available`,
   157	    };
   158	  }
   159	
   160	  // Build fallback chain: [downgraded_model, ...configured_fallbacks, configured_primary]
   161	  const fallbacks = [
   162	    ...phaseConfig.fallbacks.filter(f => f !== targetModelId),
   163	    configuredPrimary,
   164	  ].filter(f => f !== targetModelId);
   165	
   166	  return {
   167	    modelId: targetModelId,
   168	    fallbacks,
   169	    tier: requestedTier,
   170	    wasDowngraded: true,
   171	    reason: classification.reason,
   172	  };
   173	}
