   202	function getModelTier(modelId: string): ComplexityTier {
   203	  // Strip provider prefix if present
   204	  const bareId = modelId.includes("/") ? modelId.split("/").pop()! : modelId;
   205	
   206	  // Check exact match first
   207	  if (MODEL_CAPABILITY_TIER[bareId]) return MODEL_CAPABILITY_TIER[bareId];
   208	
   209	  // Check if any known model ID is a prefix/suffix match
   210	  for (const [knownId, tier] of Object.entries(MODEL_CAPABILITY_TIER)) {
   211	    if (bareId.includes(knownId) || knownId.includes(bareId)) return tier;
   212	  }
   213	
   214	  // Unknown models are assumed heavy (safest assumption)
   215	  return "heavy";
   216	}
   217	
   218	function isKnownModel(modelId: string): boolean {
   219	  const bareId = modelId.includes("/") ? modelId.split("/").pop()! : modelId;
   220	
   221	  if (MODEL_CAPABILITY_TIER[bareId]) return true;
   222	
   223	  for (const knownId of Object.keys(MODEL_CAPABILITY_TIER)) {
   224	    if (bareId.includes(knownId) || knownId.includes(bareId)) return true;
   225	  }
   226	
   227	  return false;
   228	}
