   230	function findModelForTier(
   231	  tier: ComplexityTier,
   232	  config: DynamicRoutingConfig,
   233	  availableModelIds: string[],
   234	  crossProvider: boolean,
   235	): string | null {
   236	  // 1. Check explicit tier_models config
   237	  const explicitModel = config.tier_models?.[tier];
   238	  if (explicitModel && availableModelIds.includes(explicitModel)) {
   239	    return explicitModel;
   240	  }
   241	  // Also check with provider prefix stripped
   242	  if (explicitModel) {
   243	    const match = availableModelIds.find(id => {
   244	      const bareAvail = id.includes("/") ? id.split("/").pop()! : id;
   245	      const bareExplicit = explicitModel.includes("/") ? explicitModel.split("/").pop()! : explicitModel;
   246	      return bareAvail === bareExplicit;
   247	    });
   248	    if (match) return match;
   249	  }
   250	
   251	  // 2. Auto-detect: find the cheapest available model in the requested tier
   252	  const candidates = availableModelIds
   253	    .filter(id => {
   254	      const modelTier = getModelTier(id);
   255	      return modelTier === tier;
   256	    })
   257	    .sort((a, b) => {
   258	      if (!crossProvider) return 0;
   259	      const costA = getModelCost(a);
   260	      const costB = getModelCost(b);
   261	      return costA - costB;
   262	    });
   263	
   264	  return candidates[0] ?? null;
   265	}
   266	
   267	function getModelCost(modelId: string): number {
   268	  const bareId = modelId.includes("/") ? modelId.split("/").pop()! : modelId;
   269	
   270	  if (MODEL_COST_PER_1K_INPUT[bareId] !== undefined) {
   271	    return MODEL_COST_PER_1K_INPUT[bareId];
   272	  }
   273	
   274	  // Check partial matches
   275	  for (const [knownId, cost] of Object.entries(MODEL_COST_PER_1K_INPUT)) {
   276	    if (bareId.includes(knownId) || knownId.includes(bareId)) return cost;
   277	  }
   278	
   279	  // Unknown cost — assume expensive to avoid routing to unknown cheap models
   280	  return 999;
   281	}
